class Solution:
    def longestBeautifulLanterns(self, nums):
        # 如果数组为空，返回长度 0，起点 0
        # 正常测试数据通常不会为空，这里用于增强鲁棒性
        if not nums:
            return [0, 0]

        # best_len 表示目前找到的最长连续非递增区域长度
        # best_start 表示该区域的起始位置
        best_len = 1
        best_start = 0

        # cur_len 表示当前连续非递增区域长度
        # cur_start 表示当前连续非递增区域起始位置
        cur_len = 1
        cur_start = 0

        # 从第二个灯笼开始，判断是否能接在前一个灯笼后面
        for i in range(1, len(nums)):
            if nums[i] <= nums[i - 1]:
                # 当前灯笼尺寸不超过前一个灯笼，满足非递增要求
                cur_len += 1
            else:
                # 当前灯笼尺寸大于前一个灯笼，连续区域断开
                cur_len = 1
                cur_start = i

            # 只有当前长度严格大于历史最长长度时才更新
            # 若相等则保留更靠左的历史答案
            if cur_len > best_len:
                best_len = cur_len
                best_start = cur_start

        return [best_len, best_start]
```

```java
class Solution {
    public int[] longestBeautifulLanterns(int[] nums) {
        // 如果数组为空，返回长度 0，起点 0
        // 正常测试数据通常不会为空，这里用于增强鲁棒性
        if (nums.length == 0) {
            return new int[]{0, 0};
        }

        // bestLen 表示目前找到的最长连续非递增区域长度
        // bestStart 表示该区域的起始位置
        int bestLen = 1;
        int bestStart = 0;

        // curLen 表示当前连续非递增区域长度
        // curStart 表示当前连续非递增区域起始位置
        int curLen = 1;
        int curStart = 0;

        // 从第二个灯笼开始，判断是否能接在前一个灯笼后面
        for (int i = 1; i < nums.length; i++) {
            if (nums[i] <= nums[i - 1]) {
                // 当前灯笼尺寸不超过前一个灯笼，满足非递增要求
                curLen++;
            } else {
                // 当前灯笼尺寸大于前一个灯笼，连续区域断开
                curLen = 1;
                curStart = i;
            }

            // 只有当前长度严格大于历史最长长度时才更新
            // 若相等则保留更靠左的历史答案
            if (curLen > bestLen) {
                bestLen = curLen;
                bestStart = curStart;
            }
        }

        return new int[]{bestLen, bestStart};
    }
}
